UPDATE quiz_question_template SET content = 'Dùng định nghĩa để tính đạo hàm của hàm số f(x) = $2x^{3}$ . Khi đó: a) Với bất kì x₀: $f''$(x₀) = lim [f(x)-f(x₀)]/(x-x₀). b) $f''$(1) = -6. c) $f''$(0) = 0. d) $f''$(2) = 24', payload = '{"general_hint":"Định nghĩa đạo hàm tại x₀ là giới hạn của tỉ số Δy/Δx khi Δx ->0. Khi tính giới hạn để tìm đạo hàm hàm đa thức, hãy sử dụng hằng đẳng thức (ở đây là $a^{3}$ - $b^{3}$) để triệt tiêu mẫu số (x - x₀). Sau khi có công thức đạo hàm $f''$(x) = $6x^{2}$, chỉ cần thế số để kiểm tra các câu còn lại.","sub_questions":[{"id":"a","text":"Với bất kì x₀: $f''$(x₀) = lim [f(x)-f(x₀)]/(x-x₀)","is_true":true,"explanation":"Đúng theo định nghĩa đạo hàm."},{"id":"b","text":"$f''$(1) = -6","is_true":false,"explanation":"Sai. $f''$(x) = $6x^{2}$ → $f''$(1) = 6, không phải -6."},{"id":"c","text":"$f''$(0) = 0","is_true":true,"explanation":"Đúng. $f''$(0) = 6(0)² = 0."},{"id":"d","text":"$f''$(2) = 24","is_true":true,"explanation":"Đúng. $f''$(2) = 6(4) = 24."}]}'::jsonb WHERE id = '38171940-c51d-429e-9c62-1d67053ae0fc';
UPDATE quiz_question_template SET content = 'Cho hàm số y = $x^{3}$ + $3x^{2}$ + 4x + 1 có đồ thị là (C). Số tiếp tuyến song song với đường thẳng d: y = 4x + 5 của đồ thị hàm số là', payload = '{"explanation":"$y''$ = $3x^{2}$ + 6x + 4. Ta giải phương trình $y''$(x₀) = 4: 3x₀² + 6x₀ + 4 = 4 ⇔ 3x₀(x₀ + 2) = 0. Từ đây ta tìm được hai hoành độ tiếp điểm: x₁ = 0 và x₂ = -2. Kiểm tra điều kiện trùng: Tại x₁ = 0: y = 4(x − 0) + 1 ⇒ y = 4x + 1 (thỏa). Tại x₂ = -2: y = 4(x + 2) − 3 ⇒ y = 4x + 5 (loại vì trùng d).","exact_answer":"1","accepted_answers":["1"]}'::jsonb WHERE id = '3b6851ad-c1c3-4cba-b4c5-620b3365a8e8';
