UPDATE quiz_question_template SET content = 'Một chất điểm chuyển động có phương trình S(t) = $4t^{2}$ + 2 (t tính bằng giây, S tính bằng mét). Vận tốc tức thời của chất điểm tại thời điểm t₀ = 4 (s) là: A. 32 m/s B. 34 m/s C. 36 m/s D. 8 m/s', payload = '{"options":[{"id":"A","text":"32 m/s"},{"id":"B","text":"34 m/s"},{"id":"C","text":"36 m/s"},{"id":"D","text":"8 m/s"}],"explanation":"v(t) = $S''$(t) = 8t. Tại t=4, v(4) = 84 = 32 m/s.","correct_option_id":"A"}'::jsonb WHERE id = '6d07edf7-c930-43fa-ab4f-52847b676d4a';
UPDATE quiz_question_template SET content = 'Cho hàm số y = f(x) = $2x^{3}$ có đồ thị (C) và điểm M thuộc (C) có hoành độ x0 = -1. Khi đó: a) Hệ số góc của tiếp tuyến của (C) tại điểm M bằng 6. b) Phương trình tiếp tuyến của (C) tại M đi qua điểm A(0;4). c) Phương trình tiếp tuyến của (C) tại M cắt đường thẳng d: y = 3x tại điểm có hoành độ bằng 4. d) Phương trình tiếp tuyến của (C) tại M vuông góc với đường thẳng Δ: y = -1/6 x.', payload = '{"general_hint":"Sử dụng công thức phương trình tiếp tuyến: y = $f''$(x)*(x - x₀) + y₀. Để kiểm tra tính vuông góc, tích hai hệ số góc phải bằng -1. Để tìm giao điểm của hai đường thẳng, hãy lập phương trình hoành độ giao điểm.","sub_questions":[{"id":"a","text":"Hệ số góc của tiếp tuyến của (C) tại điểm M bằng 6","is_true":true,"explanation":"Đúng. $f''$(x) = $6x^{2}$ → $f''$(-1) = 6."},{"id":"b","text":"Phương trình tiếp tuyến của (C) tại M đi qua điểm A(0;4)","is_true":true,"explanation":"Đúng. PTTT: y = 6(x+1) - 2 = 6x + 4. Thay x=0 → y = 4."},{"id":"c","text":"Phương trình tiếp tuyến của (C) tại M cắt đường thẳng d: y = 3x tại điểm có hoành độ bằng 4","is_true":false,"explanation":"Sai. 6x + 4 = 3x → x = -4/3, không phải 4."},{"id":"d","text":"Phương trình tiếp tuyến của (C) tại M vuông góc với đường thẳng Δ: y = -1/6 x","is_true":true,"explanation":"Đúng. Tích hệ số góc: 6 × (-1/6) = -1."}]}'::jsonb WHERE id = '71b9bd42-59cb-464b-97e8-9cc18008cfe6';
UPDATE quiz_question_template SET content = 'Cho hàm số y=f(x) xác định trên R và có $f''$(2)=5. Phương trình tiếp tuyến của đồ thị hàm số y=f(x) tại M(2;1) là: A. y=5x+11 B. y=5x-9 C. y=5x-11 D. y=5x+3', payload = '{"options":[{"id":"A","text":"y=5x+11"},{"id":"B","text":"y=5x-9"},{"id":"C","text":"y=5x-11"},{"id":"D","text":"y=5x+3"}],"explanation":"Thay x₀ = 2, y₀ = 1, $f''$(2) = 5 vào công thức: y = 5(x - 2) + 1 = 5x - 9","correct_option_id":"B"}'::jsonb WHERE id = '7336932d-ebc3-413a-9d58-8ec4cf30f757';
UPDATE quiz_question_template SET content = 'Một bình nuôi cấy vi sinh vật được giữ ở nhiệt độ 0°C. Nhiệt độ tăng lên theo hàm y = f(t) = $t^{2}$ + t + 1 (°C). Tính tốc độ tăng của bình tại thời điểm t = 5 giây.', payload = '{"explanation":"Sử dụng công thức đạo hàm cơ bản: ($t^{n}$)'' = n·$t^{n-1}$ ⇒ $f''$(t) = 2t + 1. Thay t = 5 vào: $f''$(5) = 10 + 1 = 11","exact_answer":"11","accepted_answers":["11"]}'::jsonb WHERE id = '92c28c6a-673c-4939-b873-f45f866f779e';
UPDATE quiz_question_template SET content = 'Cho hàm số y = $x^{2}$ + 3x + 1 có đồ thị (C). Viết được phương trình tiếp tuyến của (C) tại giao điểm của (C) với trục tung. a) Hệ số góc của phương trình tiếp tuyến bằng 3. b) Phương trình tiếp tuyến đi qua điểm A(1;3). c) Phương trình tiếp tuyến cắt đường thẳng y = 2x + 1 tại điểm có hoành độ bằng 0. d) Phương trình tiếp tuyến vuông góc với đường thẳng y = -1/3 x + 1.', payload = '{"general_hint":"Luôn bắt đầu bằng việc tìm tọa độ tiếp điểm (giao với trục tung thì x=0). Đạo hàm tại x₀ chính là hệ số góc k. Điều kiện vuông góc giữa hai đường thẳng là tích hai hệ số góc bằng -1. Để kiểm tra một điểm có thuộc đường thẳng hay không, hãy thay tọa độ điểm đó vào phương trình đường thẳng.","sub_questions":[{"id":"a","text":"Hệ số góc của phương trình tiếp tuyến bằng 3","is_true":true,"explanation":"Đúng. $f''$(x) = 2x + 3 → $f''$(0) = 3."},{"id":"b","text":"Phương trình tiếp tuyến đi qua điểm A(1;3)","is_true":false,"explanation":"Sai. PTTT: y = 3x + 1. Thay x = 1 → y = 4, không phải 3."},{"id":"c","text":"Phương trình tiếp tuyến cắt đường thẳng y = 2x + 1 tại điểm có hoành độ bằng 0","is_true":true,"explanation":"Đúng. 3x + 1 = 2x + 1 → x = 0."},{"id":"d","text":"Phương trình tiếp tuyến vuông góc với đường thẳng y = -1/3 x + 1","is_true":true,"explanation":"Đúng. Tích hệ số góc: 3 × (-1/3) = -1."}]}'::jsonb WHERE id = 'a6a7616c-1d9f-4ce6-a0ad-1e4e08b07aa6';
UPDATE quiz_question_template SET content = 'Cân nặng trung bình của một em bé trong độ tuổi từ 0 đến 36 tháng có thể được tính gần đúng bởi hàm số w(t) = $0.00076t^{3}$ − $0.06t^{2}$ + 1.8t + 8.2, trong đó t được tính bằng tháng và w được tính bằng pound. Tính tốc độ thay đổi cân nặng của em bé đó tại thời điểm 15 tháng tuổi (kết quả làm tròn đến hàng phần trăm).', payload = '{"explanation":"w''(t) = $0.00228t^{2}$ − 0.12t + 1.8. w''(15) = 0.00228 × (15)² − 0.12 × 15 + 1.8 = 0.513","exact_answer":"0.51","accepted_answers":["0.51"]}'::jsonb WHERE id = 'bc63d674-b611-410d-aaa0-4d5ba8165ed5';
