UPDATE quiz_question_template SET content = 'Tính đạo hàm (bằng định nghĩa) của hàm số y = $2x^{2}$ + x + 1 tại x₀ = 2', payload = '{"explanation":"[2($x^{2}$ − 4) + (x − 2)] / (x − 2) = 2x + 5, lim₍ₓ→₂₎ = 9","exact_answer":"9","accepted_answers":["9"]}'::jsonb WHERE id = 'd22c2fd4-20f2-48a0-8649-16163e9ef5f5';
UPDATE quiz_question_template SET content = 'Cho hàm số y = $x^{3}$ - $3x^{2}$ + 2. Viết phương trình tiếp tuyến của đồ thị hàm số biết tiếp tuyến song song với đường thẳng y = 9x + 7. A. y = 9x + 7; y = 9x - 25 B. y = 9x - 25 C. y = 9x - 7; y = 9x + 25 D. y = 9x + 25', payload = '{"options":[{"id":"A","text":"y = 9x + 7; y = 9x - 25"},{"id":"B","text":"y = 9x - 25"},{"id":"C","text":"y = 9x - 7; y = 9x + 25"},{"id":"D","text":"y = 9x + 25"}],"explanation":"$y''$ = $3x^{2}$ - 6x = 9 ⇒ x = -1, x = 3. Loại x = -1, nhận x = 3 ⇒ y = 9x - 25","correct_option_id":"B"}'::jsonb WHERE id = 'd3b3b89e-e6e6-4251-ab3e-90170bbc7a9f';
UPDATE quiz_question_template SET content = 'Cho chuyển động thẳng xác định bởi phương trình s(t) = -1/3t³ + $4t^{2}$ + 9t + 3, trong đó t tính bằng giây và s tính bằng mét. Tính quãng đường vật đi được từ lúc t = 0 đến lúc chuyển động có vận tốc bằng không.', payload = '{"explanation":"v(t) = $s''$(t) = -$t^{2}$ + 8t + 9. Khi v(t) = 0, ta có: -$t^{2}$ + 8t + 9 = 0 ⇒ t₁ = -1 (loại vì t > 0), t₂ = 9. Vậy tại t = 9 giây, vật dừng lại. Quãng đường: Δs = s(9) − s(0) = 165 − 3 = 162 (mét)","exact_answer":"162","accepted_answers":["162"]}'::jsonb WHERE id = 'd9609c97-f139-4db1-806e-23a608f3af5e';
UPDATE quiz_question_template SET content = 'Cho chuyển động s = $2t^{3}$ + $6t^{2}$ − t. Vận tốc tức thời tại t = 3 s là bao nhiêu?', payload = '{"explanation":"v(t) = $6t^{2}$ + 12t − 1. Tại t = 3, v(3) = 6(9) + 12(3) − 1 = 54 + 36 − 1 = 89","exact_answer":"89","accepted_answers":["89"]}'::jsonb WHERE id = 'dcd9b263-d3d0-4b04-accb-9f345bb84647';
UPDATE quiz_question_template SET content = 'Một chất điểm chuyển động có quãng đường s(t) = 1/4t⁴ - $t^{3}$ + 5/2t² + 10t (t > 0). Tại thời điểm gia tốc của vật đạt giá trị nhỏ nhất thì vận tốc của vật bằng bao nhiêu? A. 13 B. 11 C. 10 D. 12', payload = '{"options":[{"id":"A","text":"13"},{"id":"B","text":"11"},{"id":"C","text":"10"},{"id":"D","text":"12"}],"explanation":"v(t) = $t^{3}$ - $3t^{2}$ + 5t + 10, a(t) = $3t^{2}$ - 6t + 5. a(t) đạt min tại t = 1, khi đó v(1) = 13","correct_option_id":"A"}'::jsonb WHERE id = 'e3099963-f5da-449b-900d-0abed75819a5';
UPDATE quiz_question_template SET content = 'Cho hàm số f(x) = $x^{3}$ + 1 có đồ thị (C). Hệ số góc của tiếp tuyến của đồ thị (C) tại điểm có hoành độ x = 1 là: A. $f''$(1) = 3 B. $f''$(1) = -3 C. $f''$(1) = 4 D. $f''$(1) = -4', payload = '{"options":[{"id":"A","text":"$f''$(1) = 3"},{"id":"B","text":"$f''$(1) = -3"},{"id":"C","text":"$f''$(1) = 4"},{"id":"D","text":"$f''$(1) = -4"}],"explanation":"$f''$(x) = $3x^{2}$, suy ra $f''$(1) = 3","correct_option_id":"A"}'::jsonb WHERE id = 'fab22ebe-2c99-4c6b-b75f-953465f8c634';
UPDATE quiz_question_template SET payload = '{"general_hint":"Đạo hàm của hàm phân thức (1/u)'' = -u''/u^2. Cẩn thận dấu giá trị khi tính y₀ và k tại điểm có tọa độ âm. Hai đường thẳng vuông góc khi tích hệ số góc bằng -1. Kiểm tra giao điểm bằng cách giải phương trình hoành độ giao điểm f(x) = g(x).","sub_questions":[]}'::jsonb WHERE id = 'fd561871-2159-4173-a588-470bdcd4d35f';
UPDATE quiz_question_template SET content = 'Cho hàm số f(x) = $x^{3}$ − $3x^{2}$ + 2x. a) Hàm số có đạo hàm là $f''$(x) = $3x^{2}$ − 6x + 2 b) $f''$(3) = 6 c) $f''$(4) < $f''$(5) d) $f''$(2) + $f''$(-2) = 0', payload = '{"general_hint":"Sử dụng quy tắc ($x^{n}$)'' = n·$x^{n-1}$ để tìm đạo hàm. Để kiểm tra tính đúng sai của các giá trị, chỉ cần thay x tương ứng vào hàm số $f''$(x). Lưu ý dấu khi tính toán với số âm ở câu d.","sub_questions":[]}'::jsonb WHERE id = 'fe7f8e42-2a46-42b4-a9a4-091a03f1cee5';

